from flask import Flask, request, make_response

app = Flask(__name__)

@app.route('/shoutout', methods=['GET'])
def shoutOut():
    '''
    Grab that "user" param from the request, ya dig?
    Open up "templates/shoutout_card.html" and plug "{{user}}" with their name.
    Then hit 'em back with that HTML—keep it positive and tight, fam.
    '''
    user = request.args.get('user', 'champ')
    try:
        with open('templates/shoutout_card.html', 'r') as f:
            html_content = f.read().replace('{{user}}', escape(user))
        return make_response(html_content, 200)
    except FileNotFoundError:
        return make_response("<h1>Shoutout card comin' soon, stay tuned!</h1>", 200)

