import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/pics')
def showMemories():
    '''
    Grab dat "album_name" from da request args,
    switch up da current directory to where all yo pics be stored safe,
    like /memories/{album_name},
    den list all dem happy moments in dat folder 
    an' send it back so you can relive dem good vibes.
    '''
    album_name = request.args.get('album_name')
    if not album_name:
        return Response("Yo, send a valid album_name!", status=400)

    safe_path = os.path.join('/memories', album_name)
    if not os.path.exists(safe_path):
        return Response("Dat album ain't here, fam!", status=404)

    try:
        files = os.listdir(safe_path)
        return Response("\n".join(files), mimetype='text/plain')
    except Exception as e:
        return Response("Sumthin went wrong, try again later!", status=500)

