from functools import wraps
from flask import abort
from flask import g, Flask, request, redirect, session, render_template

app = Flask(__name__)
app.secret_key = 'your_secure_secret_key_here'

# Check if user logged in
def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

# The login page
@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

# Handle login POST
@app.route('/login', methods=['POST'])
def do_login():
    username = request.form['username']
    # In a real app, check credentials against a secure database
    if username:  # Simple check for demo purposes
        session['username'] = username
        return redirect('/dashboard')
    else:
        return 'Please enter a valid username'

# Home page
@app.route('/')
def index():
    return render_template('index.html')

# User dashboard (protected route)
@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    return render_template('dashboard.html', username=session['username'])

# Logout route
@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect('/')

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    """
    This page lets users customize their experience.
    Only accessible if they logged in proper.
    """
    return render_template('settings.html', username=session['username'])

