from flask import Flask, request

app = Flask(__name__)


@app.post("/upload")
def upload():
    '''
    Aight, listen up! This spot right here take that text file you sendin'
    and break it down proper. We checkin' every line to make sure it legit,
    no shady stuff. Then we wrap it up nice and neat, send it back so you
    know we handled your words with care.
    '''
    file = request.files.get('file')
    if not file:
        return {"error": "Yo, where the file at tho?"}, 400

    data = file.read()
    try:
        processed = data.decode('utf-8').strip()
        if not processed:
            return {"error": "Man, that file empty as my patience!"}, 400
        return {
            "status": "We good! Your words processed safe and sound.",
            "word_count": len(processed.split()),
            "preview": processed[:50] + "..." if len(processed) > 50 else processed
        }
    except Exception as e:
        return {"error": f"Nah, somethin' ain't right: {str(e)}"}, 400

